import logging
import json
import os
from datetime import datetime
from azure.functions import FunctionApp, BlobTrigger, InputStream
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient
from azure.core.messaging import CloudEvent

app = FunctionApp()

# Configuration
STORAGE_ACCOUNT_URL = os.environ.get("STORAGE_ACCOUNT_URL", "https://<storage-account>.blob.core.windows.net")
COSMOS_ENDPOINT = os.environ.get("COSMOS_ENDPOINT", "https://<cosmos-account>.documents.azure.com:443/")
COSMOS_DATABASE_NAME = os.environ.get("COSMOS_DATABASE_NAME", "ProcessedData")
COSMOS_CONTAINER_NAME = os.environ.get("COSMOS_CONTAINER_NAME", "Files")
EVENT_GRID_TOPIC_ENDPOINT = os.environ.get("EVENT_GRID_TOPIC_ENDPOINT", "https://<topic-name>.<region>.eventgrid.azure.net/api/events")

# Initialize Azure credential using Managed Identity
credential = DefaultAzureCredential()

# Initialize clients
blob_service_client = BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)
cosmos_client = CosmosClient(url=COSMOS_ENDPOINT, credential=credential)
event_grid_client = EventGridPublisherClient(endpoint=EVENT_GRID_TOPIC_ENDPOINT, credential=credential)

# Initialize Cosmos DB database and container
try:
    database = cosmos_client.create_database_if_not_exists(id=COSMOS_DATABASE_NAME)
    container = database.create_container_if_not_exists(
        id=COSMOS_CONTAINER_NAME,
        partition_key=PartitionKey(path="/fileType"),
        offer_throughput=400
    )
except Exception as e:
    logging.warning(f"Cosmos DB initialization may require setup: {e}")
    database = cosmos_client.get_database_client(COSMOS_DATABASE_NAME)
    container = database.get_container_client(COSMOS_CONTAINER_NAME)


@app.blob_trigger(arg_name="blob", path="input-files/{name}",
                  connection="AzureWebJobsStorage")
def process_blob_file(blob: InputStream):
    logging.info(f"Processing blob: {blob.name}, Size: {blob.length} bytes")
    
    try:
        # Read blob content
        blob_content = blob.read()
        
        # Process the file (example: count lines for text files, get size for others)
        file_info = process_file_content(blob_content, blob.name)
        
        # Prepare document for Cosmos DB
        document = {
            "id": generate_document_id(blob.name),
            "fileName": blob.name,
            "fileType": get_file_extension(blob.name),
            "fileSize": blob.length,
            "processedAt": datetime.utcnow().isoformat(),
            "processingStatus": "completed",
            "metadata": file_info
        }
        
        # Write to Cosmos DB
        cosmos_result = write_to_cosmos_db(document)
        logging.info(f"Document written to Cosmos DB with id: {cosmos_result['id']}")
        
        # Send notification via Event Grid
        send_event_grid_notification(blob.name, document, "FileProcessed")
        
        # Optional: Copy processed file to archive container
        archive_blob(blob.name, blob_content)
        
        logging.info(f"Successfully processed blob: {blob.name}")
        
    except Exception as e:
        logging.error(f"Error processing blob {blob.name}: {str(e)}")
        
        # Send failure notification
        error_document = {
            "id": generate_document_id(blob.name),
            "fileName": blob.name,
            "fileType": get_file_extension(blob.name),
            "processedAt": datetime.utcnow().isoformat(),
            "processingStatus": "failed",
            "error": str(e)
        }
        
        try:
            write_to_cosmos_db(error_document)
            send_event_grid_notification(blob.name, error_document, "FileProcessingFailed")
        except Exception as notification_error:
            logging.error(f"Failed to send error notification: {str(notification_error)}")
        
        raise


def process_file_content(content: bytes, file_name: str) -> dict:
    """Process file content and extract metadata"""
    file_ext = get_file_extension(file_name).lower()
    
    metadata = {
        "contentHash": hash(content),
        "rawSize": len(content)
    }
    
    # Handle text files
    if file_ext in ['.txt', '.csv', '.json', '.xml', '.log']:
        try:
            text_content = content.decode('utf-8')
            metadata['lineCount'] = text_content.count('\n') + 1
            metadata['characterCount'] = len(text_content)
            
            # For JSON files, validate structure
            if file_ext == '.json':
                try:
                    json_data = json.loads(text_content)
                    metadata['jsonValid'] = True
                    metadata['jsonKeys'] = list(json_data.keys()) if isinstance(json_data, dict) else None
                except:
                    metadata['jsonValid'] = False
                    
        except UnicodeDecodeError:
            metadata['encoding'] = 'binary'
    
    # Handle CSV files
    elif file_ext == '.csv':
        try:
            text_content = content.decode('utf-8')
            lines = text_content.split('\n')
            metadata['lineCount'] = len(lines)
            if lines:
                metadata['columnCount'] = len(lines[0].split(','))
        except:
            pass
    
    return metadata


def write_to_cosmos_db(document: dict) -> dict:
    """Write document to Cosmos DB"""
    response = container.upsert_item(body=document)
    return response


def send_event_grid_notification(file_name: str, document: dict, event_type: str):
    """Send notification to Event Grid"""
    event = CloudEvent(
        type=f"FileProcessing.{event_type}",
        source=f"/blobstorage/{file_name}",
        data={
            "fileName": file_name,
            "documentId": document.get("id"),
            "status": document.get("processingStatus"),
            "processedAt": document.get("processedAt"),
            "fileSize": document.get("fileSize"),
            "metadata": document.get("metadata", {})
        }
    )
    
    event_grid_client.send([event])
    logging.info(f"Event Grid notification sent for {file_name} with type {event_type}")


def archive_blob(blob_name: str, content: bytes):
    """Archive processed blob to archive container"""
    try:
        archive_container_name = "processed-files"
        
        # Create container if it doesn't exist
        container_client = blob_service_client.get_container_client(archive_container_name)
        try:
            container_client.create_container()
        except:
            pass  # Container already exists
        
        # Upload to archive with timestamp
        timestamp = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
        archive_blob_name = f"{timestamp}_{blob_name}"
        
        blob_client = container_client.get_blob_client(archive_blob_name)
        blob_client.upload_blob(content, overwrite=True)
        
        logging.info(f"Blob archived to {archive_container_name}/{archive_blob_name}")
    except Exception as e:
        logging.warning(f"Failed to archive blob: {str(e)}")


def generate_document_id(file_name: str) -> str:
    """Generate unique document ID"""
    timestamp = datetime.utcnow().strftime("%Y%m%d%H%M%S%f")
    safe_name = file_name.replace('/', '_').replace('\\', '_')
    return f"{safe_name}_{timestamp}"


def get_file_extension(file_name: str) -> str:
    """Extract file extension"""
    if '.' in file_name:
        return file_name[file_name.rfind('.'):]
    return 'unknown'